#include <bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
int quickpow(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)ans=ans*a;
        a=a*a;
		b>>=1;
	}
	return ans;
}
CI MAXN=5e5+5;
int n,m,f[MAXN],c=0;
vector<int> t[MAXN];
void DFS(int u,int fa)
{
    if(!fa) f[u]=f[fa]+t[u].size()+1;
    else f[u]=f[fa]+t[u].size()-1;
    FOI(s,t[u]) if(s!=fa)DFS(s,u);
}
signed main(void)
{
    IOS
    cin>>n>>m;
    FOR(i,1,m)
    {
        int u,v;
        cin>>u>>v;
        t[u].pb(v);
        t[v].pb(u);
    }
    DFS(1,0);
    FOR(i,1,n)
    {
        if(f[i]>f[c])
        {
            c=i;
        }
    }
    DFS(c,0);
    FOR(i,1,n)
    {
        if(f[i]>f[c])
        {
            c=i;
        }
    }
    cout<<f[c];
    return false;
}
